import React, { useState, useMemo } from "react";
import "./BatchDashboard.css";

function BatchDashboard({ dashboardData }) {
  const [currentPage, setCurrentPage] = useState(1);
  const [itemsPerPage, setItemsPerPage] = useState(50);
  const [searchTerm, setSearchTerm] = useState("");
  const [selectedCustomer, setSelectedCustomer] = useState(null);
  const [showCustomerDetails, setShowCustomerDetails] = useState(false);

  if (!dashboardData || !dashboardData.batchResult) {
    return (
      <div className="batch-dashboard">
        <div className="no-data-message">
          <h3>No Batch Analysis Results Available</h3>
          <p>Please run a batch analysis first from the Batch Processing section.</p>
        </div>
      </div>
    );
  }

  const { batchResult } = dashboardData;
  const { dataset_info, risk_analysis, customer_segmentation, feature_analysis, all_predictions, data_source } = batchResult;

  // Calculate percentages for risk distribution
  const totalCustomers = dataset_info.total_customers;
  const riskDistribution = risk_analysis.risk_distribution || {};

  // Filter and paginate ALL predictions
  const filteredPredictions = useMemo(() => {
    if (!all_predictions) return [];
    
    return all_predictions.filter(customer => {
      if (!searchTerm) return true;
      
      const searchLower = searchTerm.toLowerCase();
      return (
        (customer.Customer_ID && customer.Customer_ID.toString().toLowerCase().includes(searchLower)) ||
        (customer.Risk_Level && customer.Risk_Level.toLowerCase().includes(searchLower)) ||
        (customer.Predicted_Churn && customer.Predicted_Churn.toString().toLowerCase().includes(searchLower))
      );
    });
  }, [all_predictions, searchTerm]);

  // Check if search is for a specific customer ID
  const isCustomerIdSearch = useMemo(() => {
    if (!searchTerm) return false;
    // Check if search term looks like a customer ID (contains "CUST" or is a number)
    return searchTerm.toLowerCase().includes('cust') || /^\d+$/.test(searchTerm);
  }, [searchTerm]);

  // If searching for a specific customer ID and we have exactly one match, show details
  const singleCustomerMatch = useMemo(() => {
    if (!isCustomerIdSearch || filteredPredictions.length !== 1) return null;
    
    const customer = filteredPredictions[0];
    // Verify it's actually the customer we're searching for
    const customerId = customer.Customer_ID || customer.CustomerID || '';
    if (customerId.toString().toLowerCase().includes(searchTerm.toLowerCase())) {
      return customer;
    }
    return null;
  }, [filteredPredictions, searchTerm, isCustomerIdSearch]);

  // Auto-show customer details when single customer is found
  React.useEffect(() => {
    if (singleCustomerMatch && !showCustomerDetails) {
      setSelectedCustomer(singleCustomerMatch);
      setShowCustomerDetails(true);
    }
  }, [singleCustomerMatch, showCustomerDetails]);

  // Pagination calculations
  const totalPages = Math.ceil(filteredPredictions.length / itemsPerPage);
  const startIndex = (currentPage - 1) * itemsPerPage;
  const endIndex = startIndex + itemsPerPage;
  const currentPredictions = filteredPredictions.slice(startIndex, endIndex);

  // Function to download ALL customer data
  const downloadAllCustomers = async () => {
    try {
      // Show loading state
      const downloadBtn = document.querySelector('.download-all-btn');
      const originalText = downloadBtn.innerHTML;
      downloadBtn.innerHTML = '<div className="spinner-small"></div> Generating Full Report...';
      downloadBtn.disabled = true;

      console.log('Starting download process...');

      // Get the file from the original file input or global variable
      let fileToProcess = null;
      
      // Try to get file from the file input
      const fileInput = document.getElementById('batch-file');
      if (fileInput && fileInput.files && fileInput.files[0]) {
        fileToProcess = fileInput.files[0];
        console.log('File found in file input:', fileToProcess.name);
      } 
      // Try to get from global variable (set during upload)
      else if (window.uploadedBatchFile) {
        fileToProcess = window.uploadedBatchFile;
        console.log('File found in global variable:', fileToProcess.name);
      }
      // If no file found, show error
      else {
        alert("❌ No CSV file found. Please go back to 'Batch Processing' and upload your CSV file again to download the complete report.");
        downloadBtn.innerHTML = originalText;
        downloadBtn.disabled = false;
        return;
      }

      // Create FormData and append the file
      const formData = new FormData();
      formData.append('file', fileToProcess);

      console.log('Sending request to backend...');

      // Send request to backend
      const response = await fetch('http://localhost:5000/api/batch/download-report', {
        method: 'POST',
        body: formData,
      });

      console.log('Response status:', response.status);

      // Check if response is successful
      if (!response.ok) {
        const errorText = await response.text();
        console.error('Server error response:', errorText);
        
        // Try to parse as JSON if possible
        try {
          const errorJson = JSON.parse(errorText);
          throw new Error(`Server error: ${errorJson.error || errorJson.message || 'Unknown error'}`);
        } catch (e) {
          throw new Error(`HTTP error! status: ${response.status}. Server returned: ${errorText.substring(0, 100)}...`);
        }
      }

      // Check if response is CSV
      const contentType = response.headers.get('content-type');
      console.log('Content-Type:', contentType);
      
      if (!contentType || !contentType.includes('text/csv')) {
        const responseData = await response.text();
        console.error('Unexpected response type. First 200 chars:', responseData.substring(0, 200));
        throw new Error(`Expected CSV but got: ${contentType}. Please check backend server.`);
      }

      // Get the blob data
      const blob = await response.blob();
      console.log('Blob size:', blob.size, 'type:', blob.type);

      if (blob.size === 0) {
        throw new Error('Downloaded file is empty');
      }

      // Create download link
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.style.display = 'none';
      a.href = url;
      
      // Get filename from response headers or create one
      const contentDisposition = response.headers.get('content-disposition');
      let filename = 'churn_analysis_complete_report.csv';
      
      if (contentDisposition) {
        const filenameMatch = contentDisposition.match(/filename="(.+)"/);
        if (filenameMatch) {
          filename = filenameMatch[1];
        }
      }
      
      a.download = filename;
      document.body.appendChild(a);
      a.click();
      window.URL.revokeObjectURL(url);
      document.body.removeChild(a);

      console.log('✅ Download completed successfully:', filename);

      // Reset button
      downloadBtn.innerHTML = originalText;
      downloadBtn.disabled = false;

    } catch (error) {
      console.error('❌ Error downloading full report:', error);
      
      let errorMessage = 'Error downloading complete report. ';
      
      if (error.message.includes('Failed to fetch')) {
        errorMessage += 'Cannot connect to server. Please make sure the backend is running on port 5000.';
      } else if (error.message.includes('HTTP error! status: 5')) {
        errorMessage += 'Server error. Please check the backend console for details.';
      } else if (error.message.includes('HTTP error! status: 4')) {
        errorMessage += 'Client error: ' + error.message;
      } else {
        errorMessage += error.message;
      }
      
      alert(errorMessage);
      
      // Reset button on error
      const downloadBtn = document.querySelector('.download-all-btn');
      if (downloadBtn) {
        downloadBtn.innerHTML = '<span className="btn-icon">📥</span> Download Complete Report';
        downloadBtn.disabled = false;
      }
    }
  };

  // Function to handle page change
  const handlePageChange = (newPage) => {
    setCurrentPage(newPage);
  };

  // Function to handle items per page change
  const handleItemsPerPageChange = (e) => {
    setItemsPerPage(Number(e.target.value));
    setCurrentPage(1); // Reset to first page
  };

  // Function to view customer details
  const viewCustomerDetails = (customer) => {
    setSelectedCustomer(customer);
    setShowCustomerDetails(true);
  };

  // Function to close customer details
  const closeCustomerDetails = () => {
    setShowCustomerDetails(false);
    setSelectedCustomer(null);
  };

  // Function to get retention recommendation based on risk level
  const getRetentionRecommendation = (riskLevel, churnProbability) => {
    if (riskLevel === 'High Risk' || churnProbability > 0.7) {
      return [
        "🚨 Immediate personalized outreach required",
        "💼 Executive escalation within 24 hours",
        "🎁 Exclusive high-value offers",
        "📞 Direct phone call from retention team",
        "🔍 Root cause analysis of dissatisfaction"
      ];
    } else if (riskLevel === 'Moderate Risk' || (churnProbability > 0.3 && churnProbability <= 0.7)) {
      return [
        "⏰ Timed intervention within 7 days",
        "💝 Loyalty program enrollment",
        "🎯 Personalized product recommendations",
        "📊 Survey to identify pain points",
        "🔧 Friction removal in payment/app experience"
      ];
    } else {
      return [
        "⭐ Loyalty reinforcement program",
        "📢 Proactive value communication",
        "🤝 Referral program promotion",
        "📈 Upselling opportunities",
        "🎉 Regular engagement campaigns"
      ];
    }
  };

  return (
    <div className="batch-dashboard">
      {/* Customer Details Modal */}
      {showCustomerDetails && selectedCustomer && (
        <div className="customer-details-modal">
          <div className="modal-content">
            <div className="modal-header">
              <h3>👤 Customer Details</h3>
              <button className="close-btn" onClick={closeCustomerDetails}>×</button>
            </div>
            
            <div className="customer-details-content">
              <div className="customer-basic-info">
                <div className="customer-id-large">
                  {selectedCustomer.Customer_ID || selectedCustomer.CustomerID || 'Unknown ID'}
                </div>
                <div className="customer-risk-summary">
                  <div className={`risk-indicator ${selectedCustomer.Risk_Level?.toLowerCase().replace(' ', '-')}`}>
                    {selectedCustomer.Risk_Level || 'Unknown Risk'}
                  </div>
                  <div className="churn-probability">
                    Churn Probability: {(selectedCustomer.Churn_Probability * 100).toFixed(1)}%
                  </div>
                  <div className={`prediction ${selectedCustomer.Predicted_Churn ? 'churn' : 'no-churn'}`}>
                    {selectedCustomer.Predicted_Churn ? "🚨 Likely to Churn" : "✅ Likely to Stay"}
                  </div>
                </div>
              </div>

              <div className="details-grid">
                <div className="details-section">
                  <h4>📊 Customer Profile</h4>
                  <div className="profile-details">
                    <div className="detail-item">
                      <span className="detail-label">Tenure:</span>
                      <span className="detail-value">{selectedCustomer.Tenure || 'N/A'} months</span>
                    </div>
                    <div className="detail-item">
                      <span className="detail-label">Order Count:</span>
                      <span className="detail-value">{selectedCustomer.OrderCount || 'N/A'}</span>
                    </div>
                    <div className="detail-item">
                      <span className="detail-label">Cashback Amount:</span>
                      <span className="detail-value">₹{(selectedCustomer.CashbackAmount || 0).toLocaleString()}</span>
                    </div>
                    <div className="detail-item">
                      <span className="detail-label">Days Since Last Order:</span>
                      <span className="detail-value">{selectedCustomer.DaySinceLastOrder || 'N/A'} days</span>
                    </div>
                    <div className="detail-item">
                      <span className="detail-label">Satisfaction Score:</span>
                      <span className="detail-value">
                        {selectedCustomer.SatisfactionScore || 'N/A'}
                        {selectedCustomer.SatisfactionScore && (
                          <span className="score-stars">
                            {'★'.repeat(selectedCustomer.SatisfactionScore)}{'☆'.repeat(5 - selectedCustomer.SatisfactionScore)}
                          </span>
                        )}
                      </span>
                    </div>
                  </div>
                </div>

                <div className="details-section">
                  <h4>📱 Engagement Details</h4>
                  <div className="profile-details">
                    <div className="detail-item">
                      <span className="detail-label">Hours on App:</span>
                      <span className="detail-value">{selectedCustomer.HourSpendOnApp || 'N/A'} hours</span>
                    </div>
                    <div className="detail-item">
                      <span className="detail-label">Number of Devices:</span>
                      <span className="detail-value">{selectedCustomer.NumberOfDeviceRegistered || 'N/A'}</span>
                    </div>
                    <div className="detail-item">
                      <span className="detail-label">Number of Addresses:</span>
                      <span className="detail-value">{selectedCustomer.NumberOfAddress || 'N/A'}</span>
                    </div>
                    <div className="detail-item">
                      <span className="detail-label">Coupons Used:</span>
                      <span className="detail-value">{selectedCustomer.CouponUsed || 'N/A'}</span>
                    </div>
                    <div className="detail-item">
                      <span className="detail-label">Complaint Filed:</span>
                      <span className="detail-value">{selectedCustomer.Complain ? 'Yes' : 'No'}</span>
                    </div>
                  </div>
                </div>

                <div className="details-section full-width">
                  <h4>🎯 Retention Recommendations</h4>
                  <div className="recommendations-list">
                    {getRetentionRecommendation(
                      selectedCustomer.Risk_Level, 
                      selectedCustomer.Churn_Probability
                    ).map((recommendation, index) => (
                      <div key={index} className="recommendation-item">
                        {recommendation}
                      </div>
                    ))}
                  </div>
                </div>

                <div className="details-section full-width">
                  <h4>📈 Business Impact</h4>
                  <div className="business-impact">
                    <div className="impact-item">
                      <span className="impact-label">Estimated CLV:</span>
                      <span className="impact-value">
                        ₹{((selectedCustomer.OrderCount || 0) * 850 + (selectedCustomer.CashbackAmount || 0)).toLocaleString()}
                      </span>
                    </div>
                    <div className="impact-item">
                      <span className="impact-label">Potential Revenue Loss:</span>
                      <span className="impact-value">
                        ₹{(((selectedCustomer.OrderCount || 0) * 850 + (selectedCustomer.CashbackAmount || 0)) * selectedCustomer.Churn_Probability).toLocaleString()}
                      </span>
                    </div>
                    <div className="impact-item">
                      <span className="impact-label">Recommended Retention Budget:</span>
                      <span className="impact-value">
                        ₹{(((selectedCustomer.OrderCount || 0) * 850 + (selectedCustomer.CashbackAmount || 0)) * 0.15).toLocaleString()}
                      </span>
                    </div>
                  </div>
                </div>
              </div>
            </div>

            <div className="modal-footer">
              <button className="btn secondary" onClick={closeCustomerDetails}>
                Close
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="dashboard-header">
        <h2>📊 Batch Analysis Dashboard</h2>
        <div className="header-actions">
          <button 
            className="download-report-btn download-all-btn"
            onClick={downloadAllCustomers}
            title="Download complete report with all customers"
          >
            <span className="btn-icon">📥</span>
            Download Complete Report
          </button>
        </div>
      </div>

      {/* Dataset Overview */}
      <div className="section-card dataset-overview">
        <h3>📁 Dataset Overview</h3>
        <div className="dataset-stats-grid">
          <div className="stat-card">
            <div className="stat-value">{dataset_info.total_customers}</div>
            <div className="stat-label">Total Customers</div>
          </div>
          <div className="stat-card">
            <div className="stat-value">{dataset_info.total_features}</div>
            <div className="stat-label">Features Analyzed</div>
          </div>
          <div className="stat-card">
            <div className="stat-value">{dataset_info.dataset_size_kb.toFixed(1)} KB</div>
            <div className="stat-label">Dataset Size</div>
          </div>
          <div className="stat-card">
            <div className="stat-value">{risk_analysis.total_predicted_churn}</div>
            <div className="stat-label">Predicted Churn</div>
          </div>
        </div>
        
        <div className="data-source-info">
          <span className="source-label">Data Source:</span>
          <span className="source-value">{data_source === "demo" ? "Demo Data" : "Uploaded CSV"}</span>
        </div>
      </div>

      {/* Risk Analysis */}
      <div className="section-card risk-analysis">
        <h3>⚠️ Risk Analysis Summary</h3>
        <div className="risk-metrics-grid">
          <div className="risk-metric">
            <div className="metric-value">{risk_analysis.average_probability?.toFixed(3) || '0.000'}</div>
            <div className="metric-label">Average Churn Probability</div>
          </div>
          <div className="risk-metric">
            <div className="metric-value">{((risk_analysis.churn_rate || 0) * 100).toFixed(1)}%</div>
            <div className="metric-label">Overall Churn Rate</div>
          </div>
          <div className="risk-metric">
            <div className="metric-value">{customer_segmentation.high_risk_customers || 0}</div>
            <div className="metric-label">High-Risk Customers</div>
          </div>
          <div className="risk-metric">
            <div className="metric-value">₹{(customer_segmentation.potential_revenue_loss || 0).toLocaleString()}</div>
            <div className="metric-label">Potential Revenue Loss</div>
          </div>
        </div>

        {/* Risk Distribution */}
        <div className="risk-distribution">
          <h4>Risk Level Distribution</h4>
          <div className="distribution-bars">
            {Object.entries(riskDistribution).map(([riskLevel, count]) => {
              const percentage = totalCustomers > 0 ? (count / totalCustomers * 100).toFixed(1) : 0;
              let barColor = "";
              
              if (riskLevel.includes("High")) barColor = "high-risk";
              else if (riskLevel.includes("Moderate")) barColor = "medium-risk";
              else barColor = "low-risk";

              return (
                <div key={riskLevel} className="distribution-item">
                  <div className="risk-label">{riskLevel}</div>
                  <div className="bar-container">
                    <div 
                      className={`risk-bar ${barColor}`}
                      style={{ width: `${percentage}%` }}
                    >
                      <span className="bar-count">{count} customers</span>
                    </div>
                  </div>
                  <div className="risk-percentage">{percentage}%</div>
                </div>
              );
            })}
          </div>
        </div>
      </div>

      {/* Feature Analysis */}
      {feature_analysis && Object.keys(feature_analysis).length > 0 && (
        <div className="section-card feature-analysis">
          <h3>🔍 High-Risk Customer Profile</h3>
          <div className="feature-grid">
            {Object.entries(feature_analysis).slice(0, 6).map(([feature, stats]) => (
              <div key={feature} className="feature-card">
                <div className="feature-name">{feature}</div>
                <div className="feature-stats">
                  <div className="stat">
                    <span className="stat-label">Avg:</span>
                    <span className="stat-value">{(stats.mean || 0).toFixed(2)}</span>
                  </div>
                  <div className="stat">
                    <span className="stat-label">Med:</span>
                    <span className="stat-value">{(stats.median || 0).toFixed(2)}</span>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Search Info */}
      {singleCustomerMatch && (
        <div className="section-card search-info">
          <div className="search-match-found">
            <span className="search-icon">🔍</span>
            <div className="search-info-content">
              <h4>Customer Found!</h4>
              <p>
                Showing details for <strong>{singleCustomerMatch.Customer_ID || singleCustomerMatch.CustomerID}</strong>. 
                Click on any customer row to view detailed information.
              </p>
            </div>
          </div>
        </div>
      )}

      {/* ALL Predictions with Pagination */}
      <div className="section-card all-predictions">
        <div className="predictions-header">
          <h3>👥 All Customer Predictions ({totalCustomers} Total)</h3>
          <div className="predictions-controls">
            <div className="search-box">
              <input
                type="text"
                placeholder="Search by Customer ID, Risk Level, or Prediction..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="search-input"
              />
              {searchTerm && (
                <div className="search-hint">
                  💡 Tip: Search for a specific Customer ID (e.g., "CUST_1234") to view detailed customer profile
                </div>
              )}
            </div>
            <div className="pagination-controls">
              <select 
                value={itemsPerPage} 
                onChange={handleItemsPerPageChange}
                className="items-per-page-select"
              >
                <option value={20}>20 per page</option>
                <option value={50}>50 per page</option>
                <option value={100}>100 per page</option>
                <option value={200}>200 per page</option>
              </select>
              
              <div className="pagination-info">
                Showing {startIndex + 1}-{Math.min(endIndex, filteredPredictions.length)} of {filteredPredictions.length} customers
              </div>
              
              <div className="pagination-buttons">
                <button
                  onClick={() => handlePageChange(currentPage - 1)}
                  disabled={currentPage === 1}
                  className="pagination-btn"
                >
                  Previous
                </button>
                <span className="page-info">
                  Page {currentPage} of {totalPages}
                </span>
                <button
                  onClick={() => handlePageChange(currentPage + 1)}
                  disabled={currentPage === totalPages}
                  className="pagination-btn"
                >
                  Next
                </button>
              </div>
            </div>
          </div>
        </div>

        <div className="predictions-table-container">
          <div className="predictions-table">
            <table>
              <thead>
                <tr>
                  <th>Customer ID</th>
                  <th>Churn Probability</th>
                  <th>Risk Level</th>
                  <th>Prediction</th>
                  <th>Tenure</th>
                  <th>Order Count</th>
                  <th>Cashback</th>
                  <th>Days Since Last Order</th>
                  <th>Satisfaction</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {currentPredictions.map((customer, index) => {
                  const riskLevel = customer.Risk_Level || 'Unknown';
                  const churnProbability = customer.Churn_Probability || 0;
                  
                  return (
                    <tr key={index} className="customer-row">
                      <td className="customer-id">
                        {customer.Customer_ID || customer.CustomerID || `CUST_${startIndex + index + 1}`}
                      </td>
                      <td>
                        <div className="probability-bar">
                          <div 
                            className="probability-fill"
                            style={{ width: `${churnProbability * 100}%` }}
                          ></div>
                          <span className="probability-text">
                            {(churnProbability * 100).toFixed(1)}%
                          </span>
                        </div>
                      </td>
                      <td>
                        <span className={`risk-badge ${riskLevel.toLowerCase().replace(' ', '-')}`}>
                          {riskLevel}
                        </span>
                      </td>
                      <td>
                        <span className={`prediction ${customer.Predicted_Churn ? 'churn' : 'no-churn'}`}>
                          {customer.Predicted_Churn ? "🚨 Churn" : "✅ Retain"}
                        </span>
                      </td>
                      <td>{customer.Tenure || 'N/A'}</td>
                      <td>{customer.OrderCount || 'N/A'}</td>
                      <td>₹{(customer.CashbackAmount || 0).toLocaleString()}</td>
                      <td>{customer.DaySinceLastOrder || 'N/A'}</td>
                      <td>
                        <div className="satisfaction-score">
                          {customer.SatisfactionScore || 'N/A'}
                          {customer.SatisfactionScore && (
                            <span className="score-stars">
                              {'★'.repeat(customer.SatisfactionScore)}{'☆'.repeat(5 - customer.SatisfactionScore)}
                            </span>
                          )}
                        </div>
                      </td>
                      <td>
                        <button 
                          className="view-details-btn"
                          onClick={() => viewCustomerDetails(customer)}
                          title="View customer details"
                        >
                          👁️ View
                        </button>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>

        {filteredPredictions.length === 0 && (
          <div className="no-results">
            <p>No customers found matching your search criteria.</p>
          </div>
        )}
      </div>

      {/* Report Download Section */}
      <div className="section-card download-section">
        <h3>📥 Download Complete Report</h3>
        <div className="download-options">
          <div className="download-option-full">
            <h4>📊 Complete Analysis Report</h4>
            <p>Download the <strong>complete dataset</strong> with predictions for <strong>ALL {totalCustomers} customers</strong>, including churn probabilities, risk levels, and personalized retention recommendations in CSV format.</p>
            <button className="download-btn primary download-all-btn" onClick={downloadAllCustomers}>
              <span className="btn-icon">📥</span>
              Download Complete Report (All {totalCustomers} Customers)
            </button>
            <p className="download-note-small">
              <strong>Note:</strong> This will process your original CSV file and generate a complete report with all customer predictions, including additional features and detailed recommendations.
            </p>
          </div>
        </div>
        
        <div className="report-features">
          <h5>Complete Report Includes:</h5>
          <ul>
            <li>✅ <strong>ALL {totalCustomers} customers</strong> with complete predictions</li>
            <li>✅ Original customer data features</li>
            <li>✅ Churn probability percentages</li>
            <li>✅ Risk level classification (Low/Medium/High)</li>
            <li>✅ Churn prediction (Yes/No)</li>
            <li>✅ Personalized retention recommendations</li>
            <li>✅ Summary statistics and insights</li>
            <li>✅ Analysis metadata and timestamps</li>
          </ul>
        </div>
      </div>

      {/* Hidden file input for re-upload */}
      <input
        type="file"
        accept=".csv"
        id="batch-file"
        style={{ display: 'none' }}
        onChange={() => {}} // Empty handler, just for file access
      />
    </div>
  );
}

export default BatchDashboard;
